export default function DinebdLogo({
  width = 64,
  height = 64,
}: {
  width?: number;
  height?: number;
}) {
  return (
    <svg
      width={width}
      height={height}
      viewBox="0 0 130 117"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      xmlnsXlink="http://www.w3.org/1999/xlink"
    >
      <rect width="130" height="117" fill="url(#pattern0_1_3)" />
      <defs>
        <pattern
          id="pattern0_1_3"
          patternContentUnits="objectBoundingBox"
          width="1"
          height="1"
        >
          <use
            xlinkHref="#image0_1_3"
            transform="matrix(0.00307975 0 0 0.00343836 -0.269939 -0.273973)"
          />
        </pattern>
        <image
          id="image0_1_3"
          width="500"
          height="500"
          preserveAspectRatio="none"
          xlinkHref="data:image/png;base64,"
        />
      </defs>
    </svg>
  );
}
